function toggleFaq(t){t.closest(".pp-faq-item").classList.toggle("open")}document.addEventListener("DOMContentLoaded",()=>{window.PortfolioUI&&PortfolioUI.initSupportPage({title:"Help center",subtitle:"Answers for import, analysis, targets, and backups",actionsHtml:`<div class="pp-action-bar pp-action-bar-compact">
                ${PortfolioUI.actionTile({label:"Docs",icon:"fa-book",href:"docs.html"})}
                ${PortfolioUI.actionTile({label:"Contact",icon:"fa-envelope",href:"contact.html"})}
            </div>`});const t=document.getElementById("helpSearch");t&&t.addEventListener("input",()=>{const o=t.value.trim().toLowerCase();document.querySelectorAll("#helpCategories .pp-support-link-card, #faqList .pp-faq-item").forEach(e=>{const a=(e.textContent+" "+(e.dataset.keywords||"")).toLowerCase();e.style.display=!o||a.includes(o)?"":"none"})})});
